CREATE TABLE IF NOT EXISTS mp_users (id SERIAL PRIMARY KEY, name VARCHAR(200) NOT NULL, email VARCHAR(200) UNIQUE, phone VARCHAR(30) UNIQUE, password_hash VARCHAR(255), role VARCHAR(30) NOT NULL DEFAULT 'participant', avatar_url TEXT, is_verified BOOLEAN DEFAULT FALSE, verify_code VARCHAR(10), reset_code VARCHAR(10), reset_code_expires TIMESTAMP, created_at TIMESTAMP DEFAULT NOW());